import{_ as t,a as e,b as r,c as l}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as i,o as d,c as o,a2 as h}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"磁力連結使用說明","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Other/magnet-transfer.md","filePath":"zh-TW/Other/magnet-transfer.md","lastUpdated":1781962217000}'),n={name:"zh-TW/Other/magnet-transfer.md"};function s(p,a,c,b,m,u){return d(),o("div",null,[...a[0]||(a[0]=[h('<h1 id="磁力連結使用說明" tabindex="-1">磁力連結使用說明 <a class="header-anchor" href="#磁力連結使用說明" aria-label="Permalink to &quot;磁力連結使用說明&quot;">​</a></h1><p>磁力連結功能可以把磁力連結中的檔案下載下來，再自動上傳到你指定的雲端渠道。</p><p>它適合用來轉存動畫、影片、壓縮檔等內容。你只要貼上磁力連結，系統會在背景建立下載任務；下載完成後會上傳到 ImgBed，並在上傳列表顯示最終連結。</p><p><img src="'+t+'" alt="磁力連結" loading="lazy"></p><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><p>磁力連結入口在首頁上傳區。</p><p>把磁力連結貼到輸入框，模式選「轉存」，再按上傳。</p><p><img src="'+e+'" alt="上傳動畫" loading="lazy"></p><h2 id="第一次使用前" tabindex="-1">第一次使用前 <a class="header-anchor" href="#第一次使用前" aria-label="Permalink to &quot;第一次使用前&quot;">​</a></h2><p>使用前需要先在後台設定磁力轉存。</p><p>通常要準備：</p><ol><li>GitHub 帳號，用來執行下載任務。</li><li>雲端上傳渠道，例如 Google Drive、OneDrive。</li><li>要上傳到的目錄。</li><li>任務逾時時間。</li></ol><p>設定完成後，回首頁貼上磁力連結就可以開始轉存。</p><h2 id="怎麼上傳磁力連結" tabindex="-1">怎麼上傳磁力連結 <a class="header-anchor" href="#怎麼上傳磁力連結" aria-label="Permalink to &quot;怎麼上傳磁力連結&quot;">​</a></h2><ol><li>在首頁上傳框貼上磁力連結。</li><li>確認模式選「轉存」。</li><li>點上傳。</li><li>等系統建立磁力任務。</li><li>任務開始後，可在右下角「磁力任務」浮窗查看進度。</li></ol><p>下載和上傳可能需要一些時間，速度取決於資源熱度、GitHub 執行環境和選擇的雲端渠道。</p><p><img src="'+r+'" alt="磁力連結下載中" loading="lazy"></p><h2 id="完成後" tabindex="-1">完成後 <a class="header-anchor" href="#完成後" aria-label="Permalink to &quot;完成後&quot;">​</a></h2><p>任務完成後，上傳列表會顯示檔名和連結。</p><p>如果是影片會顯示影片預覽；圖片會顯示圖片預覽；其他檔案會顯示一般檔案圖示。</p><p><img src="'+l+'" alt="下載完成的影片" loading="lazy"></p><p>可以直接複製：</p><table tabindex="0"><thead><tr><th>連結類型</th><th>用途</th></tr></thead><tbody><tr><td>原始連結</td><td>直接開啟檔案</td></tr><tr><td>Markdown</td><td>貼到 Markdown 文章或說明</td></tr><tr><td>HTML</td><td>貼到網頁程式碼</td></tr><tr><td>BBCode</td><td>貼到支援 BBCode 的論壇</td></tr></tbody></table><h2 id="磁力任務浮窗" tabindex="-1">磁力任務浮窗 <a class="header-anchor" href="#磁力任務浮窗" aria-label="Permalink to &quot;磁力任務浮窗&quot;">​</a></h2><p>右下角浮窗會顯示目前任務數量、任務名稱、進度和完成狀態。</p><table tabindex="0"><thead><tr><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>等待中</td><td>任務已建立，等待執行</td></tr><tr><td>下載中</td><td>正在下載磁力資源</td></tr><tr><td>上傳中</td><td>檔案已下載好，正在上傳雲端</td></tr><tr><td>完成</td><td>檔案已上傳成功，可以複製連結</td></tr><tr><td>失敗</td><td>任務沒有成功完成，需要依提示排查</td></tr></tbody></table><h2 id="使用建議" tabindex="-1">使用建議 <a class="header-anchor" href="#使用建議" aria-label="Permalink to &quot;使用建議&quot;">​</a></h2><ul><li>磁力連結內如果有多個檔案，系統會優先顯示主要完成檔案。</li><li>大檔案需要較長時間，建議等任務完成後再重新整理頁面。</li><li>如果資源本身沒有速度，任務可能很慢或失敗。</li><li>如果雲端帳號額度不足、授權失效或目錄設定錯誤，任務也可能失敗。</li><li>影片上傳完成後，頁面預覽可能需要等幾秒載入。</li></ul><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="貼上磁力連結後沒有開始" tabindex="-1">貼上磁力連結後沒有開始 <a class="header-anchor" href="#貼上磁力連結後沒有開始" aria-label="Permalink to &quot;貼上磁力連結後沒有開始&quot;">​</a></h3><p>先確認後台已啟用磁力轉存，並選了可用的 GitHub 帳號和雲端渠道。</p><h3 id="一直下載很慢" tabindex="-1">一直下載很慢 <a class="header-anchor" href="#一直下載很慢" aria-label="Permalink to &quot;一直下載很慢&quot;">​</a></h3><p>磁力速度取決於資源本身。如果沒有可用節點，下載會很慢，甚至無法完成。</p><h3 id="上傳完成後看不到預覽" tabindex="-1">上傳完成後看不到預覽 <a class="header-anchor" href="#上傳完成後看不到預覽" aria-label="Permalink to &quot;上傳完成後看不到預覽&quot;">​</a></h3><p>先確認檔案連結可以開啟。影片有時需要瀏覽器載入一段時間，也可以直接點連結查看。</p><h3 id="任務失敗怎麼辦" tabindex="-1">任務失敗怎麼辦 <a class="header-anchor" href="#任務失敗怎麼辦" aria-label="Permalink to &quot;任務失敗怎麼辦&quot;">​</a></h3><p>檢查磁力連結是否有效、雲端渠道是否可用、上傳目錄是否正確，然後重新提交任務。</p>',37)])])}const x=i(n,[["render",s]]);export{q as __pageData,x as default};
